// // This module detects the falling edge of a 1-bit input signal and outputs a high signal for one clock cycle when a falling edge is detected.
module edge_detector(
    input clk,
    input signal,
    output reg pulse
    );

    reg signal_d;

    always @(posedge clk) begin
        signal_d <= signal;
        pulse <= signal & ~signal_d;
    end
endmodule
